struct ContentView: View {
    // IMPORTANT: Replace with your actual mobile website URL
    let mobileWebsiteURL = URL(string: "https://www.example.com")!
    let jsMessageHandlerName = "nativeApp" // This must match the name used in JavaScript

    var body: some View {
        NavigationView {
            WebView(url: mobileWebsiteURL, messageHandlerName: jsMessageHandlerName)
                .navigationTitle("Hybrid App")
                .navigationBarTitleDisplayMode(.inline)
                .edgesIgnoringSafeArea(.bottom) // Extend web view to the bottom edge
        }
    }
}

// MARK: - App Entry Point (Standard for SwiftUI)

@main
struct HybridApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

